{
  "domain_analysis": {
    "business_context": "A global logistics platform needs to display real-time earnings breakdowns to drivers. The feature intersects labor classification law, wage transparency regulation, and works council governance across three jurisdictions with fundamentally different legal frameworks. This is not a simple UI feature — it is a compensation disclosure system with legal obligations that vary by jurisdiction.",
    "bounded_context": "Driver Compensation & Earnings Transparency",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation a driver receives for accepting and completing a delivery, independent of tips or bonuses. For employees (California), this must meet or exceed minimum wage guarantees. For contractors (Indonesia), this is the agreed rate." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completing individual deliveries, which may include surge pricing, distance bonuses, or promotional incentives." },
      { "term": "Tips", "definition": "Voluntary gratuities from customers passed through to the driver. In California, tips must never be counted toward base pay or minimum wage calculations (Labor Code §351)." },
      { "term": "Deductions", "definition": "Amounts subtracted from gross earnings. For employees, deductions are heavily regulated (taxes, benefits, legally authorized withholdings). For contractors, deductions may include platform fees, equipment costs, or chargebacks." },
      { "term": "Gross Earnings", "definition": "Total compensation before deductions: base pay + per-delivery bonus + tips." },
      { "term": "Net Earnings", "definition": "Take-home amount after all deductions are applied to gross earnings." },
      { "term": "Earnings Period", "definition": "The time window over which earnings are aggregated for display — a shift, a day, a pay period. Must align with jurisdiction-specific pay period requirements." },
      { "term": "Driver Classification", "definition": "The legal status of the driver — employee or independent contractor — which determines which compensation rules, deduction rules, and transparency obligations apply." },
      { "term": "Works Council Approval", "definition": "In Germany, formal consent from the Betriebsrat required before deploying systems that affect compensation display or monitoring. This is a hard deployment gate, not a notification." },
      { "term": "Wage Statement", "definition": "In California, a legally mandated itemized document (Labor Code §226) showing gross wages, total hours, deductions, net wages, pay period, and employer information. The earnings breakdown may constitute or feed into this." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings breakdown must show all four components: base pay, per-delivery bonus, tips, and deductions. No component may be hidden or aggregated into another.",
      "invariant": true,
      "invariant_justification": "If any component is hidden, the breakdown is no longer a breakdown — it is misleading. In California this would also violate wage statement law. The entire feature's purpose is destroyed if components are merged or omitted.",
      "testable_assertion": "For any completed delivery, the earnings breakdown displays exactly four distinct line items: base pay, per-delivery bonus, tips, and deductions, and gross_earnings = base_pay + per_delivery_bonus + tips, and net_earnings = gross_earnings - total_deductions."
    },
    {
      "id": "BR-2",
      "rule": "In California, tips must never be included in base pay calculations or used to satisfy minimum wage requirements.",
      "invariant": true,
      "invariant_justification": "California Labor Code §351 prohibits employers from crediting tips against minimum wage. Violating this is wage theft — a legal liability, not a policy choice.",
      "testable_assertion": "For California drivers, the minimum wage compliance check uses only base_pay and per_delivery_bonus, never tips."
    },
    {
      "id": "BR-3",
      "rule": "In California, the earnings breakdown must meet the itemized wage statement requirements of Labor Code §226: gross wages earned, total hours worked, all deductions individually itemized, net wages earned, inclusive dates of the pay period, and employer legal name and address.",
      "invariant": true,
      "invariant_justification": "This is a statutory requirement for employees. Non-compliance triggers penalties of $50-$100 per violation per pay period, plus potential class action exposure.",
      "testable_assertion": "For California drivers, the earnings view includes or links to a statement containing: gross wages, total hours, each deduction as a separate line item with label, net wages, pay period dates, and employer identity."
    },
    {
      "id": "BR-4",
      "rule": "In Germany, the earnings transparency feature must not be deployed until the Betriebsrat (works council) has formally approved the system. This is a hard deployment gate.",
      "invariant": true,
      "invariant_justification": "Under the Betriebsverfassungsgesetz (Works Constitution Act), §87(1)(6), the works council has co-determination rights over technical systems that monitor employee performance or behavior. Deploying without approval is illegal and can result in injunctions. This is not a process preference — it is a legal precondition.",
      "testable_assertion": "The feature cannot be activated for Germany-region drivers unless a works_council_approval flag is set to true with an associated approval date and reference number."
    },
    {
      "id": "BR-5",
      "rule": "Deductions must be individually itemized with a human-readable label — never presented as a single aggregated amount.",
      "invariant": false,
      "invariant_justification": "Required by law in California (Labor Code §226), and best practice everywhere. However, in Indonesia where drivers are contractors, the level of itemization could be a policy decision. Marking as non-invariant because the exact itemization depth for non-employee jurisdictions is a business choice.",
      "testable_assertion": "Each deduction is displayed as a separate line item with a descriptive label (e.g., 'Platform Service Fee', 'Tax Withholding', 'Equipment Rental')."
    },
    {
      "id": "BR-6",
      "rule": "Earnings data must reflect real-time or near-real-time state. 'Real time' means updated within the platform's event processing latency, not batch-processed at end of day.",
      "invariant": false,
      "invariant_justification": "The spec says 'real time' but the acceptable latency window is a business/technical tradeoff. The invariant is that data must not be stale by more than one earnings event — but the exact SLA is policy.",
      "testable_assertion": "When a delivery is completed and payment is calculated, the driver's earnings breakdown reflects the new delivery within 60 seconds."
    },
    {
      "id": "BR-7",
      "rule": "Driver classification (employee vs. independent contractor) determines which set of compensation rules, deduction rules, and display requirements apply. Classification is per-jurisdiction, not per-driver-preference.",
      "invariant": true,
      "invariant_justification": "Misclassification exposes the platform to enormous legal liability. A California driver cannot be shown contractor-style earnings. The classification drives the entire rule engine and is not negotiable.",
      "testable_assertion": "A driver operating in California is always treated as an employee for earnings calculation and display purposes, regardless of any other driver attribute."
    },
    {
      "id": "BR-8",
      "rule": "In California, the earnings breakdown must include total hours worked during the earnings period.",
      "invariant": true,
      "invariant_justification": "Labor Code §226 requires hours on itemized wage statements for non-exempt employees. Since AB5 classifies gig drivers as employees, hours tracking and display is mandatory.",
      "testable_assertion": "For California drivers, the earnings breakdown includes a 'Total Hours Worked' field that is > 0 for any period with completed deliveries."
    },
    {
      "id": "BR-9",
      "rule": "Currency and locale formatting must match the driver's operating jurisdiction. California earnings in USD, Germany in EUR, Indonesia in IDR.",
      "invariant": true,
      "invariant_justification": "Displaying earnings in the wrong currency corrupts the meaning of every number shown. This is data integrity, not formatting preference.",
      "testable_assertion": "California earnings display uses USD ($) with 2 decimal places, Germany uses EUR (€) with 2 decimal places, Indonesia uses IDR (Rp) with 0 decimal places."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and individually itemized deductions as separate line items, plus total hours worked, gross wages, and net wages, with the pay period dates and employer name — all within 60 seconds of delivery completion"
    },
    {
      "id": "AC-2",
      "given": "A driver in California has earned tips during a pay period",
      "when": "The system calculates minimum wage compliance",
      "then": "Tips are excluded from the base pay calculation and displayed as an entirely separate component"
    },
    {
      "id": "AC-3",
      "given": "The platform has not received Betriebsrat approval for Germany",
      "when": "A driver in Germany attempts to access the earnings breakdown feature",
      "then": "The feature is unavailable — not degraded, not partially shown, but gated entirely — with a message explaining it is pending approval"
    },
    {
      "id": "AC-4",
      "given": "The Betriebsrat has formally approved the feature (approval date and reference recorded)",
      "when": "A driver in Germany views their earnings breakdown",
      "then": "They see the full earnings breakdown with all four components and jurisdiction-appropriate formatting in EUR"
    },
    {
      "id": "AC-5",
      "given": "A driver in Indonesia completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay, per-delivery bonus, tips, and deductions in IDR, without employee-specific fields like hours worked or employer information"
    },
    {
      "id": "AC-6",
      "given": "A driver has multiple deductions in a pay period (e.g., platform fee, tax withholding, insurance)",
      "when": "They view the deductions section",
      "then": "Each deduction is listed as a separate labeled line item — never a single lump sum"
    },
    {
      "id": "AC-7",
      "given": "A driver completes a delivery",
      "when": "They check their earnings within 60 seconds",
      "then": "The most recent delivery's earnings are reflected in the breakdown"
    },
    {
      "id": "AC-8",
      "given": "A driver operates in any jurisdiction",
      "when": "The earnings breakdown is rendered",
      "then": "The arithmetic identity holds: net_earnings = base_pay + per_delivery_bonus + tips - sum(all_deductions)"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver completes a delivery but receives zero tips",
      "expected_behavior": "Tips line item is still displayed, showing $0.00 / €0.00 / Rp0. The component is never hidden — zero is a valid value, absence of the line item is not."
    },
    {
      "scenario": "A California driver's base pay + bonus for the period falls below minimum wage per hour",
      "expected_behavior": "The system must flag this for payroll adjustment. The earnings display should show the actual base pay earned, and the minimum wage top-up must appear as a separate, labeled line item — not silently folded into base pay."
    },
    {
      "scenario": "A deduction exceeds gross earnings, resulting in negative net pay",
      "expected_behavior": "Net earnings displays as negative with clear indication the driver owes money. The system must never silently zero-out or hide a negative balance — that would be inaccurate and, in California, potentially a wage statement violation."
    },
    {
      "scenario": "Germany's works council revokes previously granted approval",
      "expected_behavior": "The feature must be immediately disabled for all German drivers. Historical earnings data remains accessible (drivers have a right to past wage information), but the real-time transparency feature is gated off."
    },
    {
      "scenario": "A driver operates across jurisdiction boundaries (e.g., picks up in one state, delivers in another)",
      "expected_behavior": "Jurisdiction is determined by the driver's employment jurisdiction, not the delivery location. A California-classified driver retains California protections regardless of where a specific delivery occurs."
    },
    {
      "scenario": "Platform fee structure changes mid-pay-period",
      "expected_behavior": "Deductions before and after the change are calculated at their respective rates. The earnings breakdown must never retroactively apply new deduction rates to previously completed deliveries."
    },
    {
      "scenario": "A tip is adjusted after initial display (customer modifies tip post-delivery)",
      "expected_behavior": "The earnings breakdown updates to reflect the adjusted tip with an audit trail. The driver should see the change, not a silent modification. In California, the adjustment must appear on the next wage statement."
    },
    {
      "scenario": "System latency causes earnings to be delayed beyond 60 seconds",
      "expected_behavior": "The UI must indicate that earnings data may be delayed — never show stale data without a staleness indicator. Showing outdated numbers as if they are current is worse than showing a loading state."
    }
  ],

  "business_impact": {
    "financial": "High. In California, non-compliant wage statements trigger penalties of $50 per employee per initial violation and $100 per subsequent violation per pay period, plus exposure to class action suits (PAGA claims can reach millions). Getting this right avoids existential legal risk. In Germany, deploying without works council approval can trigger injunctions that halt operations. Conversely, a well-executed transparency feature can reduce driver disputes and support ticket costs.",
    "operational": "Significant. The feature requires per-jurisdiction rule engines, real-time event processing, a works council approval gate for Germany, and ongoing compliance monitoring as labor laws evolve. California's AB5 classification means the platform must track hours — a fundamentally different operational model than contractor-based markets. This is not one feature with three translations; it is three distinct compliance regimes behind one UI.",
    "user": "Positive for driver trust and retention. Transparent earnings reduce disputes, increase platform trust, and improve driver satisfaction. However, poorly designed deduction visibility could increase churn if drivers see fees they previously didn't notice. The feature must be designed to build trust, not erode it.",
    "risk": "Legal risk is the dominant concern. California wage statement non-compliance, German works council violations, and misclassification liability are all high-severity risks. Secondary risk: if the 'real-time' promise is not met and drivers make financial decisions based on stale data, the platform faces both legal and reputational exposure.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally mandated wage transparency. Must see compliant itemized statements. Directly benefits from minimum wage protections being visible." },
      { "group": "Drivers (Germany)", "impact": "Feature is blocked until works council approves. If rolled out elsewhere first, German drivers may feel excluded — comms strategy needed." },
      { "group": "Drivers (Indonesia)", "impact": "Gain voluntary transparency with no legal mandate. Positive trust signal, but deduction visibility may surface fees that were previously opaque." },
      { "group": "Platform Legal/Compliance Team", "impact": "Must validate compliance per jurisdiction before launch. Ongoing obligation to update rules as laws change. Carries liability for non-compliance." },
      { "group": "German Works Council (Betriebsrat)", "impact": "Must be engaged early as co-decision-maker, not informed after the fact. Their approval is a legal precondition, not a courtesy." },
      { "group": "Payroll/Finance Team", "impact": "Earnings breakdown data must align exactly with payroll records. Any discrepancy between what drivers see and what payroll processes creates disputes and audit risk." },
      { "group": "Product/Engineering", "impact": "Must build jurisdiction-aware rule engine, not a single global feature. Architecture must support adding new jurisdictions as the platform expands." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is a single sentence ('show each driver their earnings breakdown in real time') applied to three jurisdictions with radically different legal frameworks. California alone requires a compliance-grade wage statement system — this is not mentioned in the spec. Germany requires works council approval before deployment — the spec does not acknowledge this gate. The spec treats this as one feature; in reality it is three jurisdiction-specific compliance systems behind a shared UI. Multiple critical legal requirements must be inferred rather than specified.",
    "high_confidence_areas": [
      "The four earnings components (base pay, bonus, tips, deductions) are clearly stated",
      "California AB5 employee classification and its implications are well-established law",
      "German works council co-determination rights under §87 BetrVG are settled law",
      "The arithmetic identity (net = gross - deductions) is a hard invariant"
    ],
    "low_confidence_areas": [
      "What exactly 'real time' means — event-driven, polling interval, acceptable staleness?",
      "Whether the earnings breakdown is intended to serve as the official California wage statement or supplement a separate one",
      "How deductions are defined for Indonesian contractors — platform fees? Tax withholding? Equipment?",
      "Whether the platform already tracks hours for California drivers, or if this is a new capability",
      "How multi-jurisdiction drivers are handled (driver registered in one country, delivering in another)",
      "Data retention and historical access requirements per jurisdiction"
    ],
    "assumptions": [
      "California drivers are classified as employees under AB5 and this classification is already operationalized in the platform",
      "The Betriebsrat has not yet been consulted and approval is pending",
      "Indonesian drivers are genuinely independent contractors under local law",
      "The platform already calculates these four earnings components — the feature is about display, not calculation",
      "The earnings breakdown is per-driver, not shared with other drivers or managers"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether this earnings breakdown IS the official California itemized wage statement (Labor Code §226) or a separate, supplementary view. If it IS the wage statement, it must meet strict legal formatting and delivery requirements. If it supplements a separate statement, it has more design flexibility but must not contradict the official statement.",
      "affected_stakeholders": ["Platform Legal/Compliance Team", "Drivers (California)", "Payroll/Finance Team"],
      "options": [
        "A: Treat the earnings breakdown as the official wage statement — build to full §226 compliance",
        "B: Treat it as a supplementary real-time view — require a separate compliant wage statement system",
        "C: Build it to §226 compliance anyway as defensive legal posture, even if a separate statement exists"
      ],
      "recommendation": "Option C. Build to compliance regardless. If it walks like a wage statement and quacks like a wage statement, a court will treat it as one. Defensive posture is cheaper than litigation."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define latency SLA. For a driver deciding whether to continue working or stop, the difference between 30 seconds and 5 minutes is material. For legal compliance, the difference between 'real time' and 'per pay period' determines the entire architecture.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Product/Engineering"],
      "options": [
        "A: Event-driven updates within 60 seconds of delivery completion",
        "B: Near-real-time with periodic refresh (every 5 minutes)",
        "C: Updated at end of each shift/work session"
      ],
      "recommendation": "Option A. Drivers make real-time decisions about whether to keep working based on earnings. Stale data undermines the feature's entire purpose."
    },
    {
      "type": "missing_context",
      "description": "No specification of what 'deductions' include per jurisdiction. For California employees, deductions are legally constrained (only authorized deductions). For Indonesian contractors, deductions could include platform commission, insurance, equipment — but which ones? The domain model for deductions is completely unspecified.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Platform Legal/Compliance Team", "Payroll/Finance Team"],
      "options": [
        "A: Define a fixed taxonomy of deduction types per jurisdiction",
        "B: Allow dynamic deduction types with per-jurisdiction validation rules",
        "C: Defer deduction taxonomy to implementation team"
      ],
      "recommendation": "Option A. Deduction types are a domain concern, not an implementation detail. California in particular has strict rules about what can be deducted from employee wages — this must be defined at the domain level."
    }
  ],

  "rejection_reasons": []
}

